import{_ as t,o as e,c as r,a2 as o}from"./chunks/framework.ZhLefgN8.js";const u=JSON.parse('{"title":"行情套餐","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"market-data/data-plans.md","filePath":"zh-CN/market-data/data-plans.md"}'),n={name:"market-data/data-plans.md"};function l(i,a,s,d,h,p){return e(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="行情套餐" tabindex="-1">行情套餐 <a class="header-anchor" href="#行情套餐" aria-label="Permalink to &quot;行情套餐&quot;">​</a></h1><p>美股、港股、新加坡行情套餐种类、优惠条件、延迟行情说明及权限互踢规则。</p><h2 id="美股行情" tabindex="-1">美股行情 <a class="header-anchor" href="#美股行情" aria-label="Permalink to &quot;美股行情&quot;">​</a></h2><p><strong>全美综合行情</strong>：全美 17 家交易所综合成交行情及最优买卖一档报价 OPRA<br><strong>美股深度摆盘</strong>：提供 60 档买卖盘报价，覆盖盘前、盘中、盘后及夜盘交易时段<br><strong>OPRA 美股期权行情</strong>：OPRA 美股期权实时成交行情及最优买卖一档报价</p><p>优惠条件：近 30 天美股成功交易次数 ≥ 2 次，账户总资产 ≥ 10,000 USD（或等值港币），可在兑换商城内使用任务币兑换全美综合行情。</p><h2 id="港股行情" tabindex="-1">港股行情 <a class="header-anchor" href="#港股行情" aria-label="Permalink to &quot;港股行情&quot;">​</a></h2><p><strong>LV2 高级行情</strong>：港交所股票实时成交行情及十档买卖盘报价，适用于移动端、桌面端（限中国大陆）</p><p>优惠：开户后赠送港股 LV2 实时行情（仅限使用大陆网络用户）。</p><h2 id="新加坡行情" tabindex="-1">新加坡行情 <a class="header-anchor" href="#新加坡行情" aria-label="Permalink to &quot;新加坡行情&quot;">​</a></h2><p><strong>LV1 实时行情</strong>：新加坡股票实时成交行情及一档买卖盘报价</p><p>优惠：新加坡本地用户开户赠送 LV1 实时行情。</p><h2 id="延迟行情说明" tabindex="-1">延迟行情说明 <a class="header-anchor" href="#延迟行情说明" aria-label="Permalink to &quot;延迟行情说明&quot;">​</a></h2><p>已开户未入金客户为延迟行情：</p><ul><li>港股延迟行情：自选仅支持显示 20 只股票手动刷新实时行情，超过部分显示延迟 15 分钟行情，无盘口数据、经纪队列、异动数据</li><li>美股延迟行情：OTC 股票 15 分钟延时行情</li></ul><h2 id="行情权限互踢" tabindex="-1">行情权限互踢 <a class="header-anchor" href="#行情权限互踢" aria-label="Permalink to &quot;行情权限互踢&quot;">​</a></h2><p>应交易所要求，多端同时登录一个账号时仅允许一个设备查看高级实时行情权限。</p><p>互踢是指新登录设备占用了已登录旧设备的高级行情，旧设备被降为基础行情。被踢设备页面会给出提示及重启按钮，点击可重新占用高级权限。</p><h2 id="收费说明" tabindex="-1">收费说明 <a class="header-anchor" href="#收费说明" aria-label="Permalink to &quot;收费说明&quot;">​</a></h2><p>iOS 因平台抽成定价会比 Android 和电脑端略贵。</p>',19)])])}const _=t(n,[["render",l]]);export{u as __pageData,_ as default};
